const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient({
    endpoint: process.env.COSMOS_DB_ENDPOINT,
    key: process.env.COSMOS_DB_KEY
});

const database = cosmosClient.database(process.env.COSMOS_DB_DATABASE);
const container = database.container(process.env.COSMOS_DB_CONTAINER);

async function processBatch(items) {
    const results = [];
    for (const item of items) {
        try {
            const processed = {
                ...item,
                processed: true,
                processedAt: new Date().toISOString(),
                transformedData: item.data ? item.data.toUpperCase() : '',
                calculatedValue: item.value ? item.value * 2 : 0
            };
            results.push(processed);
        } catch (error) {
            results.push({
                ...item,
                error: error.message,
                processed: false
            });
        }
    }
    return results;
}

async function updateCosmosDB(processedItems) {
    const updatePromises = processedItems.map(async (item) => {
        try {
            await container.item(item.id, item.partitionKey).replace(item);
            return { success: true, id: item.id };
        } catch (error) {
            return { success: false, id: item.id, error: error.message };
        }
    });
    return await Promise.all(updatePromises);
}

async function getAllItems(continuationToken = null) {
    const querySpec = {
        query: "SELECT * FROM c WHERE c.processed != true OR NOT IS_DEFINED(c.processed)"
    };
    
    const options = {
        maxItemCount: 1000
    };
    
    if (continuationToken) {
        options.continuationToken = continuationToken;
    }
    
    const { resources, hasMoreResults, continuationToken: newToken } = 
        await container.items.query(querySpec, options).fetchNext();
    
    return { items: resources, hasMoreResults, continuationToken: newToken };
}

app.http('batchDataProcessor', {
    methods: ['GET', 'POST'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        context.log('Starting batch data processing...');
        
        const startTime = Date.now();
        const maxExecutionTime = 9 * 60 * 1000;
        
        let totalProcessed = 0;
        let totalErrors = 0;
        let continuationToken = null;
        let hasMoreResults = true;
        const batchSize = 100;
        
        try {
            while (hasMoreResults) {
                const elapsedTime = Date.now() - startTime;
                if (elapsedTime > maxExecutionTime) {
                    context.log(`Approaching timeout limit. Processed ${totalProcessed} items so far.`);
                    break;
                }
                
                const { items, hasMoreResults: moreResults, continuationToken: newToken } = 
                    await getAllItems(continuationToken);
                
                hasMoreResults = moreResults;
                continuationToken = newToken;
                
                if (items.length === 0) {
                    context.log('No more items to process');
                    break;
                }
                
                context.log(`Retrieved ${items.length} items for processing`);
                
                for (let i = 0; i < items.length; i += batchSize) {
                    const currentElapsedTime = Date.now() - startTime;
                    if (currentElapsedTime > maxExecutionTime) {
                        context.log(`Timeout approaching during batch processing`);
                        break;
                    }
                    
                    const batch = items.slice(i, i + batchSize);
                    context.log(`Processing batch ${Math.floor(i / batchSize) + 1} with ${batch.length} items`);
                    
                    const processedBatch = await processBatch(batch);
                    const updateResults = await updateCosmosDB(processedBatch);
                    
                    const successCount = updateResults.filter(r => r.success).length;
                    const errorCount = updateResults.filter(r => !r.success).length;
                    
                    totalProcessed += successCount;
                    totalErrors += errorCount;
                    
                    context.log(`Batch completed: ${successCount} successful, ${errorCount} errors`);
                }
                
                if (Date.now() - startTime > maxExecutionTime) {
                    break;
                }
            }
            
            const totalExecutionTime = (Date.now() - startTime) / 1000;
            
            const response = {
                status: 'completed',
                totalProcessed: totalProcessed,
                totalErrors: totalErrors,
                executionTimeSeconds: totalExecutionTime,
                hasMoreData: hasMoreResults,
                continuationToken: continuationToken,
                message: hasMoreResults 
                    ? 'Processing incomplete due to timeout. Continuation token available for next run.'
                    : 'All data processed successfully'
            };
            
            context.log('Batch processing completed:', response);
            
            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(response)
            };
            
        } catch (error) {
            context.log.error('Error during batch processing:', error);
            
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    status: 'error',
                    error: error.message,
                    totalProcessed: totalProcessed,
                    totalErrors: totalErrors,
                    executionTimeSeconds: (Date.now() - startTime) / 1000
                })
            };
        }
    }
});

